content.hob:
(let [note (get-item (:id item))]
  [:div {:style "padding: 16px; font-family: system-ui, sans-serif;"}
    [:h1 {:style "margin: 0 0 8px 0;"} (:name note)]
    [:p {:style "color: #888; font-size: 0.8em; margin: 0 0 16px 0;"}
      (str "ID: " (:id note))]
    [:div {:style "white-space: pre-wrap; line-height: 1.5;"}
      (or (get-in note [:content :description]) "(no content)")]])
